import { useState } from "react";
import { motion } from "framer-motion";
import { Wine, Beer, Martini, UtensilsCrossed, Flame, IceCream } from "lucide-react";
import Footer from "../components/Footer";

// Menu Categories and Items - with complete descriptions
const menuCategories = [
  {
    id: "salad",
    name: "Salad",
    icon: UtensilsCrossed,
    items: [
      { name: "Classic Caesar Salad", description: "Romaine lettuce, croutons, parmesan, Caesar dressing", price: "₹429" },
      { name: "Fruit Salad", description: "Seasonal fruits with honey yogurt dressing", price: "₹449" },
      { name: "Burrata Arugula Salad", description: "Creamy burrata, rocket, cherry tomatoes, balsamic glaze", price: "₹850" },
      { name: "Green Salad", description: "Mixed greens, cucumber, tomatoes, house vinaigrette", price: "₹199" },
    ]
  },
  {
    id: "sushi",
    name: "Sushi",
    icon: Wine,
    items: [
      { name: "Shiitake Mushroom Nigiri", description: "Shiitake mushrooms on vinegared rice", price: "₹499" },
      { name: "Veg California Roll", description: "Avocado, cucumber, carrot inside-out roll", price: "₹549" },
      { name: "Edamame California Roll", description: "Edamame, avocado, cucumber roll", price: "₹549" },
      { name: "Avocado Tempura Uramaki", description: "Tempura avocado inside-out roll", price: "₹549" },
      { name: "Crab Stick Nigiri", description: "Crab stick on vinegared rice", price: "₹499" },
      { name: "Prawn Tempura Uramaki", description: "Tempura prawn inside-out roll", price: "₹599" },
      { name: "Chicken Teriyaki Futomaki", description: "Teriyaki chicken thick roll", price: "₹599" },
      { name: "Smoked Salmon Maki", description: "Smoked salmon thin roll with cucumber", price: "₹699" },
    ]
  },
  {
    id: "fries-nachos",
    name: "Fries & Nachos",
    icon: Flame,
    items: [
      { name: "Peri Peri Fries", description: "Spicy peri peri seasoned fries", price: "₹249" },
      { name: "Truffle French Fry", description: "Crispy fries with truffle aioli", price: "₹399" },
      { name: "Loaded Nachos", description: "Cheese, jalapeños, salsa, sour cream", price: "₹549 / 599" },
    ]
  },
  {
    id: "oriental-starters",
    name: "Oriental Starters",
    icon: Martini,
    items: [
      { name: "Golden Fried Baby Corn", description: "Crispy fried baby corn fritters", price: "₹199" },
      { name: "Corn Salt & Pepper", description: "Corn kernels tossed with salt & pepper", price: "₹249" },
      { name: "Crackling Spinach", description: "Crispy flash-fried spinach leaves", price: "₹249" },
      { name: "Crispy Chilli Baby Corn", description: "Baby corn in spicy chilli sauce", price: "₹299" },
      { name: "Chilli Lotus Stem", description: "Crispy lotus stem with green chillies", price: "₹299" },
      { name: "Sesame Paneer Sticks", description: "Sesame-coated paneer fingers", price: "₹299" },
      { name: "Crispy Konjee Vegetable", description: "Mixed vegetables in spicy batter", price: "₹349" },
      { name: "Schezwan Paneer Dry", description: "Schezwan spiced cottage cheese", price: "₹399" },
      { name: "Soya Chilli Mushroom", description: "Button mushrooms in soya chilli", price: "₹449" },
      { name: "Drums of Heaven", description: "Crispy chicken lollipops", price: "₹349" },
      { name: "Honey Chilli Chicken", description: "Sweet-spicy honey chilli chicken", price: "₹349" },
      { name: "Cilantro Chilli Chicken", description: "Chicken with coriander and chillies", price: "₹349" },
      { name: "Chicken Wings", description: "Spicy fried chicken wings", price: "₹349" },
      { name: "Tangra Style Chilli Chicken", description: "Bengali-style chilli chicken", price: "₹399" },
      { name: "Chicken Yakitori", description: "Japanese grilled chicken skewers", price: "₹449" },
      { name: "Steamed Fish", description: "Steamed fish with ginger soy", price: "₹449" },
      { name: "Kung Pao Chicken", description: "Sichuan chicken with peanuts", price: "₹499" },
      { name: "Golden Fried Prawn", description: "Crispy fried prawns", price: "₹499" },
      { name: "Butter Chilli Garlic Prawns", description: "Prawns in butter garlic chilli", price: "₹499" },
      { name: "Pan Fried Chilli Fish", description: "Pan-fried fish fillets with chillies", price: "₹599" },
      { name: "Honey Soya Pork Belly", description: "Slow-cooked pork belly", price: "₹599" },
    ]
  },
  // ... (rest of categories with descriptions)
];

// Image map matching actual files
const menuImageMap = {
  "salad": "salad.jpg",
  "sushi": "sushi.jpg",
  "fries-nachos": "fries_nachos.jpg",
  "oriental-starters": "oriental_starters.jpg",
  "starters": "starters.jpg",
  "mains": "main_course.jpg",
  "pizza": "pizza.jpg",
  "cocktails": "cocktails.jpg",
  "whiskey": "whiskey.jpg",
  "beer": "beer.jpg",
  "desserts": "dessert.jpg"
};

const categoryImages = Object.fromEntries(
  Object.entries(menuImageMap).map(([key, value]) => [key, `/assets/menu_images/${value}`])
);

const MenuPage = () => {
  const [activeCategory, setActiveCategory] = useState("salad");

  const activeMenuCategory = menuCategories.find(cat => cat.id === activeCategory);

  return (
    <main className="bg-black min-h-screen pt-24 md:pt-32">
      {/* Hero */}
      <section className="max-w-[1400px] mx-auto px-6 md:px-12 pb-12">
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          className="text-center"
        >
          <span className="font-accent text-gold text-sm tracking-[0.3em] uppercase">
            Culinary Excellence
          </span>
          <h1 className="font-heading text-5xl md:text-7xl text-white mt-4 mb-6">
            Our Menu
          </h1>
          <p className="font-body text-zinc-400 text-lg max-w-2xl mx-auto">
            From handcrafted cocktails to gourmet cuisine, discover flavors that 
            define the Corridor experience.
          </p>
        </motion.div>
      </section>

      {/* Category Navigation */}
      <section className="max-w-[1400px] mx-auto px-6 md:px-12 pb-8">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.2 }}
          className="flex flex-wrap justify-center gap-3 md:gap-4"
        >
          {menuCategories.map((category) => {
            const IconComponent = category.icon;
            return (
              <button
                key={category.id}
                onClick={() => setActiveCategory(category.id)}
                className={`flex items-center gap-2 px-4 md:px-6 py-2.5 font-body text-xs md:text-sm tracking-[0.1em] uppercase transition-all duration-300 border ${
                  activeCategory === category.id
                    ? "bg-gold text-black border-gold"
                    : "bg-transparent text-white border-zinc-700 hover:border-gold hover:text-gold"
                }`}
              >
                <IconComponent size={16} />
                <span className="hidden sm:inline">{category.name}</span>
                <span className="sm:hidden">{category.name.split(' ')[0]}</span>
              </button>
            );
          })}
        </motion.div>
      </section>

      {/* Menu Content */}
      <section className="max-w-[1400px] mx-auto px-6 md:px-12 pb-24">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Category Image */}
          <motion.div
            key={`image-${activeCategory}`}
            initial={{ opacity: 0, x: -30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6 }}
            className="lg:col-span-1"
          >
            <div className="relative h-[350px] md:h-[450px] lg:h-[550px] overflow-hidden border border-zinc-800">
              <img
                src={categoryImages?.[activeCategory] || "/assets/menu_images/salad.jpg"}
                alt={activeMenuCategory?.name || "Menu"}
                className="w-full h-full object-cover brightness-110 contrast-110"
                loading="lazy"
                onError={(e) => {
                  e.target.src = "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?ixlib=rb-4.0.3";
                }}
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent" />
              <div className="absolute bottom-0 left-0 right-0 p-6">
                <h3 className="font-heading text-3xl text-white drop-shadow-lg">
                  {activeMenuCategory?.name}
                </h3>
              </div>
            </div>
          </motion.div>

          {/* Menu Items */}
          <motion.div
            key={`items-${activeCategory}`}
            initial={{ opacity: 0, x: 30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6 }}
            className="lg:col-span-2"
          >
            <div className="space-y-1">
              {activeMenuCategory?.items.map((item, index) => (
                <motion.div
                  key={item.name}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.4, delay: index * 0.05 }}
                  className="group p-6 border-b border-zinc-800 hover:bg-zinc-900/50 transition-colors duration-300"
                >
                  <div className="flex justify-between items-start gap-4">
                    <div className="flex-1">
                      <h4 className="font-heading text-xl text-white group-hover:text-gold transition-colors">
                        {item.name}
                      </h4>
                      <p className="font-body text-sm text-zinc-500 mt-1">
                        {item.description || 'Delicious selection from our kitchen'}
                      </p>
                    </div>
                    <div className="font-heading text-xl text-gold whitespace-nowrap">
                      {item.price}
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          </motion.div>
        </div>
      </section>

      {/* Note */}
      <section className="bg-zinc-900/50 py-8">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 text-center">
          <p className="font-body text-sm text-zinc-500">
            * Prices inclusive of all taxes. Menu items subject to availability.
            <br />
            For dietary restrictions or allergies, please inform our staff.
          </p>
        </div>
      </section>

      {/* CTA */}
      <section className="bg-black py-16">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 text-center">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            viewport={{ once: true }}
          >
            <h2 className="font-heading text-3xl md:text-4xl text-white mb-6">
              Ready to Experience Our Menu?
            </h2>
            <a
              href="https://www.zomato.com/kolkata/corridor-bar-kitchen-chowringhee/book"
              target="_blank"
              rel="noopener noreferrer"
              className="inline-block bg-gold text-black px-10 py-4 font-body text-sm tracking-[0.2em] uppercase hover:bg-white transition-all duration-300"
            >
              Reserve Your Table
            </a>
          </motion.div>
        </div>
      </section>

      <Footer />
    </main>
  );
};

export default MenuPage;
